import { Field, Form, useFormik } from "formik";

const AdminResult = ()  =>
{
    const formik = useFormik({
        initialValues :{
                homeTeam: '', 
                awayTeam: '',
                season: ''},
        onSubmit : values => {
          alert(JSON.stringify(values, null, 2));}
        }   
    );

    return(

        <>
        <div>hi</div>
        <div>           
            <Form onSubmit={formik.handleSubmit}>
                 <Field type="text" {...formik.getFieldProps("homeTeam")}/> 
                 <Field type="text" {...formik.getFieldProps("awayTeam")}/> 
                 <Field type="text" {...formik.getFieldProps("season")}/> 
  
            </Form>            
        </div>
        </>
    );
}

export default AdminResult;

